// pages/TopicDetail.jsx — Full topic content: explanation, formulas, shortcuts, questions
import React, { useState, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import { getTopicBySlug } from "../data/topicsData";
import { useAI } from "../hooks/useAI";
import { markTopicComplete } from "../utils/progress";
import QuestionItem from "../components/QuestionItem";

export default function TopicDetail() {
  const { topicName } = useParams();
  const localTopic = getTopicBySlug(topicName);

  // State: current content (starts with local data, can be replaced by AI)
  const [content, setContent] = useState(
    localTopic
      ? {
          explanation: localTopic.explanation,
          formulas: localTopic.formulas,
          shortcuts: localTopic.shortcuts,
          questions: localTopic.questions,
        }
      : null
  );

  const { generateTopicContent, loading, error } = useAI();

  // Mark as "viewed" once the page loads
  useEffect(() => {
    if (localTopic) markTopicComplete(localTopic.slug);
  }, [localTopic]);

  // Handle AI generation
  const handleGenerate = async () => {
    const displayName = localTopic?.name || topicName;
    const aiData = await generateTopicContent(displayName);
    if (aiData) setContent(aiData);
  };

  if (!localTopic && !content) {
    return (
      <main className="max-w-3xl mx-auto px-5 py-12">
        <p className="text-muted text-sm">
          Topic not found.{" "}
          <Link to="/" className="text-accent hover:underline">
            Back to Home
          </Link>
        </p>
      </main>
    );
  }

  const displayName = localTopic?.name || topicName;

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">
      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-xs text-muted mb-8">
        <Link to="/" className="hover:text-gray-300 transition-colors">
          Home
        </Link>
        <span>/</span>
        <span className="text-gray-300">{displayName}</span>
      </div>

      {/* Page title */}
      <h1 className="text-2xl font-semibold text-white mb-2">{displayName}</h1>
      {localTopic && (
        <p className="text-xs font-mono text-muted mb-8">{localTopic.category}</p>
      )}

      {content ? (
        <>
          {/* ── Explanation ─────────────────────────────── */}
          <section className="mb-10">
            <h2 className="text-xs font-mono text-muted uppercase tracking-widest mb-3">
              Explanation
            </h2>
            <p className="text-gray-300 text-sm leading-relaxed">{content.explanation}</p>
          </section>

          {/* ── Formulas ────────────────────────────────── */}
          <section className="mb-10">
            <h2 className="text-xs font-mono text-muted uppercase tracking-widest mb-3">
              Key Formulas
            </h2>
            <ul className="space-y-2 list-none m-0 p-0">
              {content.formulas.map((f, i) => (
                <li key={i} className="flex items-start gap-3">
                  <span className="text-accent font-mono text-xs mt-0.5 shrink-0">
                    {String(i + 1).padStart(2, "0")}
                  </span>
                  <span className="font-mono text-sm text-gray-200 leading-relaxed">
                    {f}
                  </span>
                </li>
              ))}
            </ul>
          </section>

          {/* ── Shortcuts ───────────────────────────────── */}
          <section className="mb-10">
            <h2 className="text-xs font-mono text-muted uppercase tracking-widest mb-3">
              Shortcuts & Tips
            </h2>
            <ul className="space-y-2 list-none m-0 p-0">
              {content.shortcuts.map((s, i) => (
                <li key={i} className="flex items-start gap-3 text-sm text-gray-400">
                  <span className="text-accent shrink-0">›</span>
                  {s}
                </li>
              ))}
            </ul>
          </section>

          {/* ── Practice Questions ──────────────────────── */}
          <section className="mb-10">
            <h2 className="text-xs font-mono text-muted uppercase tracking-widest mb-1">
              Practice Questions
            </h2>
            <p className="text-xs text-muted mb-5">Click an option to reveal the answer.</p>
            {content.questions.map((q, i) => (
              <QuestionItem key={q.id || i} question={q} index={i} />
            ))}
          </section>
        </>
      ) : (
        <p className="text-muted text-sm mb-8">No local data. Generate content with AI below.</p>
      )}

      {/* ── AI Generate Button ──────────────────────── */}
      <div className="border-t border-border pt-8">
        <p className="text-xs text-muted mb-3">
          Generate richer content using AI (Groq LLaMA):
        </p>
        <button
          onClick={handleGenerate}
          disabled={loading}
          className="bg-surface border border-border hover:border-accent text-sm text-gray-300 hover:text-white px-5 py-2.5 rounded transition-all disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {loading ? "Generating…" : "⚡ Generate with AI"}
        </button>
        {error && (
          <p className="mt-3 text-xs text-red-400">Error: {error}</p>
        )}
      </div>

      {/* Bottom nav */}
      <div className="mt-12">
        <Link to="/" className="text-xs text-muted hover:text-gray-300 transition-colors">
          ← Back to all topics
        </Link>
      </div>
    </main>
  );
}
